def set_pvc_name(manifest, pvc_name) do
  manifest
  |> update_in(["spec", Access.key("volumes", [])], fn volumes ->
    volume = %{
      "name" => @pvc_name_volume_name,
      "persistentVolumeClaim" => %{"claimName" => pvc_name}
    }

    [volume | volumes]
  end)
  |> update_in(
    ["spec", "containers", access_main_container(), Access.key("volumeMounts", [])],
    fn volume_mounts ->
      [%{"name" => @pvc_name_volume_name, "mountPath" => "/home/livebook"} | volume_mounts]
    end
  )
end

def manifest(pvc, namespace) do
  %{
    "apiVersion" => "v1",
    "kind" => "PersistentVolumeClaim",
    "metadata" => %{"name" => pvc.name, "namespace" => namespace},
    "spec" => %{
      "storageClassName" => pvc.storage_class,
      "accessModes" => [pvc.access_mode],
      "resources" => %{"requests" => %{"storage" => "#{pvc.size_gb}Gi"}}
    }
  }
end

