def from_compressed(string) when is_binary(string) do
  {:insert, string}
end
def from_compressed(length) when is_integer(length) and length >= 0 do
  {:retain, length}
end
def from_compressed(length) when is_integer(length) and length < 0 do
  {:delete, -length}
end

def insert(string) do
  {:insert, string}
end

def retain(length) do
  {:retain, length}
end

def split_at(op, position)
def split_at({:insert, string}, position) do
  {part_one, part_two} = Livebook.Text.JS.split_at(string, position)
  {insert(part_one), insert(part_two)}
end
def split_at({:retain, length}, position) do
  {retain(position), retain(length - position)}
end
def split_at({:delete, length}, position) do
  {delete(position), delete(length - position)}
end

